package com.example.documentviewer;

import android.content.ContentResolver;
import android.content.Intent;
import android.database.Cursor;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.provider.OpenableColumns;
import android.view.View;
import android.view.ViewGroup;
import android.webkit.MimeTypeMap;
import android.widget.FrameLayout;
import android.widget.ImageView;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.io.FileNotFoundException;
import java.io.IOException;
import java.io.InputStream;

public class DocumentViewActivity extends AppCompatActivity {

    private FrameLayout root;
    private TextView info;
    private ImageView imageView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        root = new FrameLayout(this);
        root.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));

        imageView = new ImageView(this);
        imageView.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        imageView.setVisibility(View.GONE);

        info = new TextView(this);
        info.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        ));
        int pad = (int) (16 * getResources().getDisplayMetrics().density);
        info.setPadding(pad, pad, pad, pad);

        root.addView(imageView);
        root.addView(info);

        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(@Nullable Intent intent) {
        if (intent == null) {
            showError("No intent.");
            return;
        }

        String action = intent.getAction();
        if (!Intent.ACTION_VIEW.equals(action)) {
            showError("Unsupported action: " + action);
            return;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            showError("No data URI.");
            return;
        }

        String mime = intent.getType();
        if (mime == null) mime = guessMime(uri);

        String name = queryDisplayName(uri);
        String header = "URI: " + uri + "\n" +
                "Name: " + (name != null ? name : "(unknown)") + "\n" +
                "MIME: " + (mime != null ? mime : "(unknown)");

        if (mime != null && mime.equalsIgnoreCase("application/pdf")) {
            renderPdfFirstPage(uri, header);
        } else if (mime != null && mime.startsWith("image/")) {
            renderImage(uri, header);
        } else {
            showError(header + "\n\nUnsupported type.");
        }
    }

    private void renderImage(Uri uri, String header) {
        InputStream is = null;
        try {
            is = getContentResolver().openInputStream(uri);
            if (is == null) {
                showError(header + "\n\nUnable to open input stream.");
                return;
            }
            Bitmap bmp = BitmapFactory.decodeStream(is);
            if (bmp == null) {
                showError(header + "\n\nUnable to decode image.");
                return;
            }
            imageView.setImageBitmap(bmp);
            imageView.setVisibility(View.VISIBLE);
            info.setText(header);
        } catch (FileNotFoundException e) {
            showError(header + "\n\nFile not found: " + e.getMessage());
        } finally {
            if (is != null) {
                try { is.close(); } catch (IOException ignored) {}
            }
        }
    }

    private void renderPdfFirstPage(Uri uri, String header) {
        ParcelFileDescriptor pfd = null;
        PdfRenderer renderer = null;
        PdfRenderer.Page page = null;
        try {
            pfd = getContentResolver().openFileDescriptor(uri, "r");
            if (pfd == null) {
                showError(header + "\n\nUnable to open file descriptor.");
                return;
            }

            renderer = new PdfRenderer(pfd);
            if (renderer.getPageCount() <= 0) {
                showError(header + "\n\nEmpty PDF.");
                return;
            }

            page = renderer.openPage(0);

            int width = Math.max(1, page.getWidth());
            int height = Math.max(1, page.getHeight());
            Bitmap bitmap = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888);
            page.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);

            imageView.setImageBitmap(bitmap);
            imageView.setVisibility(View.VISIBLE);
            info.setText(header + "\nPages: " + renderer.getPageCount() + "\nShowing: 1");
        } catch (SecurityException e) {
            showError(header + "\n\nPermission denied: " + e.getMessage());
        } catch (IOException e) {
            showError(header + "\n\nPDF error: " + e.getMessage());
        } finally {
            if (page != null) {
                try { page.close(); } catch (Exception ignored) {}
            }
            if (renderer != null) {
                try { renderer.close(); } catch (Exception ignored) {}
            }
            if (pfd != null) {
                try { pfd.close(); } catch (Exception ignored) {}
            }
        }
    }

    private void showError(String msg) {
        imageView.setVisibility(View.GONE);
        imageView.setImageDrawable(null);
        info.setText(msg);
    }

    private String guessMime(Uri uri) {
        ContentResolver cr = getContentResolver();
        String mime = cr.getType(uri);
        if (mime != null) return mime;

        String ext = null;
        String path = uri.getPath();
        if (path != null) {
            int dot = path.lastIndexOf('.');
            if (dot >= 0 && dot < path.length() - 1) ext = path.substring(dot + 1);
        }
        if (ext == null) return null;

        ext = ext.toLowerCase();
        return MimeTypeMap.getSingleton().getMimeTypeFromExtension(ext);
    }

    private String queryDisplayName(Uri uri) {
        Cursor c = null;
        try {
            c = getContentResolver().query(uri, new String[]{OpenableColumns.DISPLAY_NAME}, null, null, null);
            if (c != null && c.moveToFirst()) {
                int idx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME);
                if (idx >= 0) return c.getString(idx);
            }
        } catch (Exception ignored) {
        } finally {
            if (c != null) c.close();
        }
        return null;
    }
}

